class ExperimentTracker:
    def __init__(self):
        self.runs = []

    def log_run(self, name, params, metrics):
        self.runs.append({
            'name': name,
            'params': params,
            'metrics': metrics
        })

    def get_best_run(self):
        best_run = None
        best_acc = -1
        for run in self.runs:
            acc = run['metrics']['accuracy']
            if acc > best_acc:
                best_acc = acc
                best_run = run
        return best_run

tracker = ExperimentTracker()
tracker.log_run("Run_1", {'lr': 0.1}, {'accuracy': 0.82})
tracker.log_run("Run_2", {'lr': 0.01}, {'accuracy': 0.91})
tracker.log_run("Run_3", {'lr': 0.001}, {'accuracy': 0.88})

best = tracker.get_best_run()
print(f"Best Run: {best['name']} with Accuracy {best['metrics']['accuracy']}")

